#### **Solution B(a): 3-to-8 Decoder — Behavioral (7 marks)**

```vhdl
LIBRARY ieee;
USE ieee.std_logic_1164.all;

ENTITY decoder3to8 IS
    PORT ( a   : IN  STD_LOGIC_VECTOR(2 DOWNTO 0);
           en  : IN  STD_LOGIC;
           y   : OUT STD_LOGIC_VECTOR(7 DOWNTO 0));
END decoder3to8;

ARCHITECTURE behavioral OF decoder3to8 IS
BEGIN
    PROCESS (a, en)
    BEGIN
        IF en = '1' THEN
            CASE a IS
                WHEN "000" => y <= "00000001";
                WHEN "001" => y <= "00000010";
                WHEN "010" => y <= "00000100";
                WHEN "011" => y <= "00001000";
                WHEN "100" => y <= "00010000";
                WHEN "101" => y <= "00100000";
                WHEN "110" => y <= "01000000";
                WHEN OTHERS => y <= "10000000";
            END CASE;
        ELSE
            y <= (OTHERS => '0');
        END IF;
    END PROCESS;
END behavioral;
```

**Mark distribution:**
